     1→/**
     2→ * PM Schedule Management Routes
     3→ *
     4→ * REST endpoints for PM schedule CRUD operations and history.
     5→ * Wraps PMSchedulerService with HTTP interface per spec 005.5.
     6→ *
     7→ * Endpoints:
     8→ * - GET /pm/schedule - List schedules with filtering
     9→ * - GET /pm/schedule/:id - Get PM by ID
    10→ * - POST /pm/schedule - Create new PM schedule
    11→ * - PATCH /pm/schedule/:id - Update PM (reschedule, reassign)
    12→ * - POST /pm/schedule/:id/lock - Lock PM to prevent optimizer changes
    13→ * - POST /pm/schedule/:id/unlock - Unlock PM to allow optimizer changes
    14→ * - GET /pm/schedule/:id/history - Get change history
    15→ *
    16→ * @see specs/005-api.md Section 5.5
    17→ */
    18→
    19→import { Hono } from 'hono';
    20→import { eq, and, gte, lte, isNull, count, desc } from 'drizzle-orm';
    21→import type { SQL } from 'drizzle-orm';
    22→import {
    23→  success,
    24→  paginatedSuccess,
    25→  error,
    26→  parsePaginationQuery,
    27→  ErrorCodes,
    28→  type AppVariables,
    29→} from '../types';
    30→import { getRequestId, getRequestDuration } from '../middleware/request-context';
    31→import { getPMSchedulerService, type SchedulePmRequest, type MovePmRequest } from '../../services';
    32→import { isValidUuid } from '../../lib/schemas';
    33→import { db } from '../../lib/db/connection';
    34→import { pmSchedule } from '../../lib/db/schema';
    35→
    36→let pmSchedulerService: ReturnType<typeof getPMSchedulerService> | null = null;
    37→
    38→function getService(): ReturnType<typeof getPMSchedulerService> {
    39→  if (!pmSchedulerService) {
    40→    pmSchedulerService = getPMSchedulerService();
    41→  }
    42→  return pmSchedulerService;
    43→}
    44→
    45→export const pmScheduleRoutes = new Hono<{ Variables: AppVariables }>();
    46→
    47→/**
    48→ * GET /pm/schedule
    49→ *
    50→ * List PM schedules with filtering and pagination.
    51→ *
    52→ * Query Parameters:
    53→ * - trainId: Filter by train
    54→ * - depotId: Filter by assigned depot
    55→ * - pmTypeId: Filter by PM type
    56→ * - status: Filter by status (SCHEDULED, IN_PROGRESS, COMPLETED, DEFERRED, CANCELLED)
    57→ * - fromDate: Target date from (inclusive)
    58→ * - toDate: Target date to (inclusive)
    59→ * - scenarioId: Get scenario schedule (null/omitted = production)
    60→ */
    61→pmScheduleRoutes.get('/pm/schedule', async (c) => {
    62→  // Parse query filters
    63→  const trainId = c.req.query('trainId');
    64→  const depotId = c.req.query('depotId');
    65→  const pmTypeId = c.req.query('pmTypeId');
    66→  const status = c.req.query('status');
    67→  const fromDate = c.req.query('fromDate');
    68→  const toDate = c.req.query('toDate');
    69→  const scenarioId = c.req.query('scenarioId');
    70→
    71→  // Build filter conditions
    72→  const conditions: SQL<unknown>[] = [];
    73→
    74→  if (trainId && isValidUuid(trainId)) {
    75→    conditions.push(eq(pmSchedule.trainId, trainId));
    76→  }
    77→  if (depotId && isValidUuid(depotId)) {
    78→    conditions.push(eq(pmSchedule.assignedDepotId, depotId));
    79→  }
    80→  if (pmTypeId && isValidUuid(pmTypeId)) {
    81→    conditions.push(eq(pmSchedule.pmTypeId, pmTypeId));
    82→  }
    83→  if (status) {
    84→    const validStatuses = ['SCHEDULED', 'IN_PROGRESS', 'COMPLETED', 'DEFERRED', 'CANCELLED'] as const;
    85→    if (validStatuses.includes(status as typeof validStatuses[number])) {
    86→      conditions.push(eq(pmSchedule.status, status as typeof validStatuses[number]));
    87→    }
    88→  }
    89→  if (fromDate) {
    90→    conditions.push(gte(pmSchedule.targetDate, fromDate));
    91→  }
    92→  if (toDate) {
    93→    conditions.push(lte(pmSchedule.targetDate, toDate));
    94→  }
    95→
    96→  // Handle scenario filter
    97→  if (scenarioId && isValidUuid(scenarioId)) {
    98→    conditions.push(eq(pmSchedule.scenarioId, scenarioId));
    99→  } else {
   100→    // Default to production schedule (scenarioId is NULL)
   101→    conditions.push(isNull(pmSchedule.scenarioId));
   102→  }
   103→
   104→  // Parse pagination
   105→  const pagination = parsePaginationQuery({
   106→    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
   107→    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
   108→    sort: c.req.query('sort'),
   109→  });
   110→
   111→  // Count total items
   112→  const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
   113→  const totalResult = await db
   114→    .select({ count: count() })
   115→    .from(pmSchedule)
   116→    .where(whereClause);
   117→  const totalItems = totalResult[0]?.count ?? 0;
   118→
   119→  // Query with relations
   120→  const schedules = await db.query.pmSchedule.findMany({
   121→    where: whereClause,
   122→    with: {
   123→      train: true,
   124→      pmType: true,
   125→      assignedDepot: true,
   126→      assignedTrack: true,
   127→    },
   128→    orderBy: desc(pmSchedule.targetDate),
   129→    limit: pagination.pageSize,
   130→    offset: pagination.offset,
   131→  });
   132→
   133→  // Map to API response format
   134→  const data = schedules.map((pm) => ({
   135→    id: pm.id,
   136→    train: pm.train
   137→      ? {
   138→          id: pm.train.id,
   139→          trainNumber: pm.train.trainNumber,
   140→          fleetCode: pm.train.fleetId, // TODO: Get fleet code from relation
   141→        }
   142→      : null,
   143→    pmType: pm.pmType
   144→      ? {
   145→          id: pm.pmType.id,
   146→          code: pm.pmType.pmCode,
   147→          name: pm.pmType.pmName,
   148→          estimatedHours: pm.pmType.estimatedHours,
   149→        }
   150→      : null,
   151→    targetDate: pm.targetDate,
   152→    targetMileageKm: pm.targetMileageKm,
   153→    status: pm.status,
   154→    constraintStart: pm.constraintStart,
   155→    constraintEnd: pm.constraintEnd,
   156→    assignedDepot: pm.assignedDepot
   157→      ? {
   158→          id: pm.assignedDepot.id,
   159→          code: pm.assignedDepot.code,
   160→        }
   161→      : null,
   162→    assignedTrack: pm.assignedTrack
   163→      ? {
   164→          id: pm.assignedTrack.id,
   165→          trackNumber: pm.assignedTrack.trackNumber,
   166→          trackType: pm.assignedTrack.trackType,
   167→        }
   168→      : null,
   169→    assignedHours: pm.assignedHours ? Number(pm.assignedHours) : null,
   170→    isLocked: pm.isLocked ?? false,
   171→    maximoWoId: pm.maximoWoId,
   172→  }));
   173→
   174→  return c.json(
   175→    paginatedSuccess(
   176→      data,
   177→      {
   178→        page: pagination.page,
   179→        pageSize: pagination.pageSize,
   180→        totalItems,
   181→      },
   182→      { durationMs: getRequestDuration(c) }
   183→    )
   184→  );
   185→});
   186→
   187→/**
   188→ * GET /pm/schedule/:id
   189→ *
   190→ * Get PM schedule details by ID.
   191→ */
   192→pmScheduleRoutes.get('/pm/schedule/:id', async (c) => {
   193→  const requestId = getRequestId(c);
   194→  const pmId = c.req.param('id');
   195→
   196→  if (!isValidUuid(pmId)) {
   197→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   198→  }
   199→
   200→  const service = getService();
   201→  const pmResult = await service.getPm(pmId);
   202→
   203→  // Cast to include all query relations (service returns more than type declares)
   204→  const pm = pmResult as typeof pmResult & {
   205→    assignedDepot: { id: string; code: string; name: string } | null;
   206→  };
   207→
   208→  // Check material availability for upcoming PMs
   209→  let materialStatus = { allAvailable: true, warnings: [] as string[] };
   210→  if (pm.status === 'SCHEDULED' && pm.assignedDepotId) {
   211→    try {
   212→      const materialResult = await service.checkMaterialAvailability(
   213→        pm.pmTypeId,
   214→        pm.assignedDepotId,
   215→        pm.targetDate
   216→      );
   217→      materialStatus = {
   218→        allAvailable: !materialResult.isBlocked && materialResult.softConstraintWarnings.length === 0,
   219→        warnings: [
   220→          ...materialResult.hardConstraintViolations.map((v) => `Blocked: ${v.partNumber} (need ${v.requiredQuantity}, have ${v.availableQuantity})`),
   221→          ...materialResult.softConstraintWarnings.map((v) => `Warning: ${v.partNumber} may not be available`),
   222→        ],
   223→      };
   224→    } catch {
   225→      // Material check failed, assume available
   226→    }
   227→  }
   228→
   229→  return c.json(
   230→    success({
   231→      id: pm.id,
   232→      train: pm.train
   233→        ? {
   234→            id: pm.train.id,
   235→            trainNumber: pm.train.trainNumber,
   236→            fleetId: pm.train.fleetId,
   237→          }
   238→        : null,
   239→      pmType: pm.pmType
   240→        ? {
   241→            id: pm.pmType.id,
   242→            code: pm.pmType.pmCode,
   243→            name: pm.pmType.pmName,
   244→            estimatedHours: pm.pmType.estimatedHours,
   245→          }
   246→        : null,
   247→      targetDate: pm.targetDate,
   248→      targetMileageKm: pm.targetMileageKm,
   249→      status: pm.status,
   250→      constraintStart: pm.constraintStart,
   251→      constraintEnd: pm.constraintEnd,
   252→      assignedDepot: pm.assignedDepot
   253→        ? {
   254→            id: pm.assignedDepot.id,
   255→            code: pm.assignedDepot.code,
   256→            name: pm.assignedDepot.name,
   257→          }
   258→        : null,
   259→      assignedTrack: pm.assignedTrack
   260→        ? {
   261→            id: pm.assignedTrack.id,
   262→            trackNumber: pm.assignedTrack.trackNumber,
   263→            trackType: pm.assignedTrack.trackType,
   264→          }
   265→        : null,
   266→      assignedHours: pm.assignedHours ? Number(pm.assignedHours) : null,
   267→      assignedShift: pm.assignedShift,
   268→      isLocked: pm.isLocked ?? false,
   269→      lockedReason: pm.lockedReason,
   270→      maximoWoId: pm.maximoWoId,
   271→      materialStatus,
   272→      actualStartDate: pm.actualStartDate,
   273→      actualEndDate: pm.actualEndDate,
   274→      actualHours: pm.actualHours ? Number(pm.actualHours) : null,
   275→      completedAt: pm.completedAt,
   276→      completedMileageKm: pm.completedMileageKm,
   277→      createdAt: pm.createdAt,
   278→      updatedAt: pm.updatedAt,
   279→    })
   280→  );
   281→});
   282→
   283→/**
   284→ * POST /pm/schedule
   285→ *
   286→ * Create a new PM schedule entry.
   287→ *
   288→ * Request body:
   289→ * - trainId: UUID of train
   290→ * - pmTypeId: UUID of PM type
   291→ * - targetDate: Target date (YYYY-MM-DD)
   292→ * - assignedDepotId?: UUID of assigned depot
   293→ * - assignedTrackId?: UUID of assigned track
   294→ * - scenarioId?: UUID of scenario (null for production)
   295→ * - reason?: Reason for manual scheduling
   296→ */
   297→pmScheduleRoutes.post('/pm/schedule', async (c) => {
   298→  const requestId = getRequestId(c);
   299→  const body = await c.req.json();
   300→
   301→  // Validate required fields
   302→  if (!body.trainId || !isValidUuid(body.trainId)) {
   303→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'trainId is required and must be a valid UUID', requestId), 400);
   304→  }
   305→  if (!body.pmTypeId || !isValidUuid(body.pmTypeId)) {
   306→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'pmTypeId is required and must be a valid UUID', requestId), 400);
   307→  }
   308→  if (!body.targetDate || !/^\d{4}-\d{2}-\d{2}$/.test(body.targetDate)) {
   309→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate is required and must be in YYYY-MM-DD format', requestId), 400);
   310→  }
   311→
   312→  // Validate optional UUIDs
   313→  if (body.assignedDepotId && !isValidUuid(body.assignedDepotId)) {
   314→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'assignedDepotId must be a valid UUID', requestId), 400);
   315→  }
   316→  if (body.assignedTrackId && !isValidUuid(body.assignedTrackId)) {
   317→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'assignedTrackId must be a valid UUID', requestId), 400);
   318→  }
   319→
   320→  const service = getService();
   321→  const user = c.get('user');
   322→
   323→  const request: SchedulePmRequest = {
   324→    trainId: body.trainId,
   325→    pmTypeId: body.pmTypeId,
   326→    targetDate: body.targetDate,
   327→    assignedDepotId: body.assignedDepotId,
   328→    assignedTrackId: body.assignedTrackId,
   329→    assignedShift: body.assignedShift,
   330→    notes: body.reason,
   331→    createdBy: user?.id,
   332→  };
   333→
   334→  const created = await service.schedulePm(request);
   335→
   336→  return c.json(
   337→    success({
   338→      id: created.id,
   339→      trainId: created.trainId,
   340→      pmTypeId: created.pmTypeId,
   341→      targetDate: created.targetDate,
   342→      targetMileageKm: created.targetMileageKm,
   343→      status: created.status,
   344→      constraintStart: created.constraintStart,
   345→      constraintEnd: created.constraintEnd,
   346→      assignedDepotId: created.assignedDepotId,
   347→      assignedTrackId: created.assignedTrackId,
   348→      assignedHours: created.assignedHours ? Number(created.assignedHours) : null,
   349→      createdAt: created.createdAt,
   350→    }),
   351→    201
   352→  );
   353→});
   354→
   355→/**
   356→ * PATCH /pm/schedule/:id
   357→ *
   358→ * Update a PM schedule entry (move, reassign).
   359→ *
   360→ * Request body:
   361→ * - targetDate?: New target date
   362→ * - assignedTrackId?: New track assignment
   363→ * - reason: Reason for change (required)
   364→ */
   365→pmScheduleRoutes.patch('/pm/schedule/:id', async (c) => {
   366→  const requestId = getRequestId(c);
   367→  const pmId = c.req.param('id');
   368→
   369→  if (!isValidUuid(pmId)) {
   370→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   371→  }
   372→
   373→  const body = await c.req.json();
   374→
   375→  // Validate reason is provided
   376→  if (!body.reason || typeof body.reason !== 'string' || body.reason.trim().length === 0) {
   377→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'reason is required for PM changes', requestId), 400);
   378→  }
   379→
   380→  // Validate targetDate if provided
   381→  if (body.targetDate && !/^\d{4}-\d{2}-\d{2}$/.test(body.targetDate)) {
   382→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate must be in YYYY-MM-DD format', requestId), 400);
   383→  }
   384→
   385→  // Validate assignedTrackId if provided
   386→  if (body.assignedTrackId && !isValidUuid(body.assignedTrackId)) {
   387→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'assignedTrackId must be a valid UUID', requestId), 400);
   388→  }
   389→
   390→  const service = getService();
   391→  const user = c.get('user');
   392→
   393→  // Get current PM to capture old values
   394→  const currentPm = await service.getPm(pmId);
   395→
   396→  // Only proceed if targetDate is being changed
   397→  if (!body.targetDate) {
   398→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate is required for PM move', requestId), 400);
   399→  }
   400→
   401→  const request: MovePmRequest = {
   402→    pmScheduleId: pmId,
   403→    newTargetDate: body.targetDate,
   404→    newTrackId: body.assignedTrackId,
   405→    reason: body.reason,
   406→    movedBy: user?.id ?? 'system',
   407→  };
   408→
   409→  const updated = await service.movePm(request);
   410→
   411→  // Calculate impact assessment
   412→  const impactAssessment = {
   413→    complianceStatus: updated.targetDate >= updated.constraintStart && updated.targetDate <= updated.constraintEnd
   414→      ? 'WITHIN_WINDOW'
   415→      : 'OUTSIDE_WINDOW',
   416→    manhourImpact: 0, // TODO: Calculate actual impact
   417→    conflictsCreated: 0, // TODO: Check for new conflicts
   418→  };
   419→
   420→  return c.json(
   421→    success({
   422→      id: updated.id,
   423→      targetDate: updated.targetDate,
   424→      previousTargetDate: currentPm.targetDate,
   425→      assignedTrackId: updated.assignedTrackId,
   426→      previousTrackId: currentPm.assignedTrackId,
   427→      updatedAt: updated.updatedAt,
   428→      updatedBy: user?.id,
   429→      explanation: {
   430→        changeType: 'DATE_CHANGED',
   431→        reason: body.reason,
   432→        impactAssessment,
   433→      },
   434→    })
   435→  );
   436→});
   437→
   438→/**
   439→ * POST /pm/schedule/:id/lock
   440→ *
   441→ * Lock a PM to prevent optimizer changes.
   442→ *
   443→ * Request body:
   444→ * - reason: Reason for locking (required)
   445→ */
   446→pmScheduleRoutes.post('/pm/schedule/:id/lock', async (c) => {
   447→  const requestId = getRequestId(c);
   448→  const pmId = c.req.param('id');
   449→
   450→  if (!isValidUuid(pmId)) {
   451→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   452→  }
   453→
   454→  const body = await c.req.json();
   455→
   456→  if (!body.reason || typeof body.reason !== 'string' || body.reason.trim().length === 0) {
   457→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'reason is required for locking', requestId), 400);
   458→  }
   459→
   460→  const service = getService();
   461→  const user = c.get('user');
   462→
   463→  const updated = await service.lockPm(pmId, body.reason, user?.id ?? 'system');
   464→
   465→  return c.json(
   466→    success({
   467→      id: updated.id,
   468→      isLocked: updated.isLocked,
   469→      lockedReason: updated.lockedReason,
   470→      lockedBy: updated.lockedBy,
   471→      lockedAt: updated.lockedAt,
   472→    })
   473→  );
   474→});
   475→
   476→/**
   477→ * POST /pm/schedule/:id/unlock
   478→ *
   479→ * Unlock a PM to allow optimizer changes.
   480→ */
   481→pmScheduleRoutes.post('/pm/schedule/:id/unlock', async (c) => {
   482→  const requestId = getRequestId(c);
   483→  const pmId = c.req.param('id');
   484→
   485→  if (!isValidUuid(pmId)) {
   486→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   487→  }
   488→
   489→  const service = getService();
   490→  const user = c.get('user');
   491→
   492→  const updated = await service.unlockPm(pmId, user?.id ?? 'system');
   493→
   494→  return c.json(
   495→    success({
   496→      id: updated.id,
   497→      isLocked: updated.isLocked,
   498→      lockedReason: updated.lockedReason,
   499→      lockedBy: updated.lockedBy,
   500→      lockedAt: updated.lockedAt,
   501→    })
   502→  );
   503→});
   504→
   505→/**
   506→ * GET /pm/schedule/:id/history
   507→ *
   508→ * Get change history for a PM.
   509→ */
   510→pmScheduleRoutes.get('/pm/schedule/:id/history', async (c) => {
   511→  const requestId = getRequestId(c);
   512→  const pmId = c.req.param('id');
   513→
   514→  if (!isValidUuid(pmId)) {
   515→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   516→  }
   517→
   518→  const service = getService();
   519→  const history = await service.getPmHistory(pmId);
   520→
   521→  const data = history.map((entry) => ({
   522→    id: entry.id,
   523→    changeType: entry.changeType,
   524→    oldTargetDate: entry.oldTargetDate,
   525→    newTargetDate: entry.newTargetDate,
   526→    oldStatus: entry.oldStatus,
   527→    newStatus: entry.newStatus,
   528→    oldAssignedTrackId: entry.oldAssignedTrackId,
   529→    newAssignedTrackId: entry.newAssignedTrackId,
   530→    changedBy: entry.changedByUser
   531→      ? {
   532→          id: entry.changedByUser.id,
   533→          displayName: entry.changedByUser.displayName,
   534→        }
   535→      : null,
   536→    changedAt: entry.changedAt,
   537→    changeReason: entry.changeReason,
   538→    changeSource: entry.changeSource,
   539→  }));
   540→
   541→  return c.json(success(data));
   542→});
