   522→  /**
   523→   * Calculate PM due dates for all PM types for a train.
   524→   */
   525→  async calculateAllPmDue(trainId: string): Promise<PmDueResult[]> {
   526→    return this.traced('calculateAllPmDue', async (span) => {
   527→      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
   528→
   529→      // Get train with fleet
   530→      const train = await this.db.query.trains.findFirst({
   531→        where: eq(trains.id, trainId),
   532→      });
   533→
   534→      if (!train) {
   535→        throw new TrainNotFoundError(trainId);
   536→      }
   537→
   538→      // Get all active PM types for this fleet
   539→      const pmTypesList = await this.db.query.pmTypes.findMany({
   540→        where: and(
   541→          eq(pmTypes.fleetId, train.fleetId),
   542→          eq(pmTypes.active, true)
   543→        ),
   544→        orderBy: [desc(pmTypes.intervalKm)],
   545→      });
   546→
   547→      const results: PmDueResult[] = [];
   548→
   549→      for (const pmType of pmTypesList) {
   550→        const dueResult = await this.calculateComplianceWindow(trainId, pmType.id);
   551→        results.push(dueResult);
   552→      }
   553→
   554→      // Sort by due date (most urgent first)
   555→      results.sort((a, b) => {
   556→        const aDate = a.complianceWindow.idealDate;
   557→        const bDate = b.complianceWindow.idealDate;
   558→        return aDate.localeCompare(bDate);
   559→      });
   560→
   561→      span.setAttribute('result.pmCount', results.length);
   562→      span.setAttribute('result.overdueCount', results.filter(r => r.isOverdue).length);
   563→
   564→      return results;
   565→    });
   566→  }
