   784→
   785→      const conditions: SQL<unknown>[] = [
   786→        eq(pmSchedule.assignedTrackId, trackId),
   787→        inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
   788→        isNull(pmSchedule.scenarioId),
