   938→        return {
   939→          isLocked: true,
   940→          workOrderId: pm.maximoWoId,
   941→          maximoStatus: null,
   942→          reason: pm.lockedReason ?? 'Manually locked',
   943→        };
   944→      }
   945→
   946→      // Check Maximo work order status
   947→      if (pm.maximoWoId) {
   948→        // In a full implementation, we would query Maximo for status
   949→        // For now, check if status is IN_PROGRESS
   950→        if (pm.status === 'IN_PROGRESS') {
