  1418→          rule: 'pm_already_locked',
  1419→          context: { lockedBy: existing.lockedBy, lockedAt: existing.lockedAt },
  1420→        });
  1421→      }
  1422→
  1423→      const [updated] = await tx
  1424→        .update(pmSchedule)
  1425→        .set({
  1426→          isLocked: true,
  1427→          lockedReason: reason,
