  1434→
  1435→      // Create audit history
  1436→      const historyRecord: NewPmScheduleHistory = {
  1437→        pmScheduleId,
  1438→        changeType: 'LOCKED',
  1439→        changedBy: lockedBy,
  1440→        changeReason: reason,
  1441→        changeSource: 'USER',
  1442→      };
  1443→
  1444→      await tx.insert(pmScheduleHistory).values(historyRecord);
  1445→
  1446→      this.log.info(
  1447→        { pmScheduleId, reason, lockedBy },
  1448→        `PM locked: ${pmScheduleId}`
  1449→      );
  1450→
  1451→      return updated;
  1452→    });
  1453→  }
  1454→
  1455→  /**
  1456→   * Unlock a PM to allow optimizer changes.
  1457→   */
  1458→  async unlockPm(pmScheduleId: string, unlockedBy: string): Promise<PmScheduleRecord> {
  1459→    return this.inTransaction('unlockPm', async (tx, span) => {
  1460→      span.setAttribute('pm.scheduleId', pmScheduleId);
  1461→
  1462→      const existing = await tx.query.pmSchedule.findFirst({
  1463→        where: eq(pmSchedule.id, pmScheduleId),
  1464→      });
  1465→
  1466→      if (!existing) {
  1467→        throw new PmScheduleNotFoundError(pmScheduleId);
  1468→      }
  1469→
  1470→      if (!existing.isLocked) {
  1471→        throw new BusinessRuleError('PM is not locked', {
  1472→          rule: 'pm_not_locked',
  1473→        });
  1474→      }
  1475→
  1476→      // Cannot unlock if Maximo work order is in progress
  1477→      if (existing.maximoWoId && existing.status === 'IN_PROGRESS') {
  1478→        throw new MaximoLockError(
  1479→          'Cannot unlock PM with in-progress Maximo work order',
  1480→          {
  1481→            workOrderId: existing.maximoWoId,
  1482→            maximoStatus: 'INPRG',
  1483→          }
  1484→        );
  1485→      }
  1486→
  1487→      const [updated] = await tx
  1488→        .update(pmSchedule)
  1489→        .set({
  1490→          isLocked: false,
  1491→          lockedReason: null,
  1492→          lockedBy: null,
  1493→          lockedAt: null,
  1494→          updatedAt: new Date(),
  1495→        })
  1496→        .where(eq(pmSchedule.id, pmScheduleId))
  1497→        .returning();
  1498→
  1499→      // Create audit history
  1500→      const historyRecord: NewPmScheduleHistory = {
  1501→        pmScheduleId,
  1502→        changeType: 'UNLOCKED',
  1503→        changedBy: unlockedBy,
  1504→        changeReason: 'Manual unlock',
  1505→        changeSource: 'USER',
  1506→      };
  1507→
  1508→      await tx.insert(pmScheduleHistory).values(historyRecord);
  1509→
  1510→      this.log.info(
  1511→        { pmScheduleId, unlockedBy },
  1512→        `PM unlocked: ${pmScheduleId}`
  1513→      );
  1514→
  1515→      return updated;
  1516→    });
  1517→  }
